/**
 * SmartMind Turbo — SPA-like navigation for Moodle.
 *
 * Hand-built AMD wrapper around amd/src/turbo.js. Not minified on purpose
 * so it stays debuggable. Re-generate manually when src changes.
 *
 * @module theme_smartmind/turbo
 */
define([], function() {

    var SWAP_SELECTOR = '#page-content';
    var SEC_NAV_SELECTOR = '.secondary-navigation';
    var PAGE_HEADER_SELECTOR = '.smartmind-page-banner';
    // Primary nav must be swapped so the "active" highlight refreshes.
    // List of selectors — all matching elements get swapped from the new doc.
    var PRIMARY_NAV_SELECTORS = ['nav.smgp-topnav', '.primary-navigation'];
    var PROGRESS_ID = 'sm-turbo-progress';

    var BYPASS_PATTERNS = [
        /\/login\//,
        /\/admin\//,
        /\/pluginfile\.php/,
        /\/draftfile\.php/,
        /\/tokenpluginfile\.php/,
        /logout\.php/,
        /\.zip$/,
        /\.pdf$/,
        /\/mod\/quiz\//,
        /\/mod\/scorm\//,
        /\/mod\/h5pactivity\//,
        /\/mod\/lesson\//,
        /\/mod\/assign\//,
        /\/mod\/bigbluebuttonbn\//,
        /[?&]edit=1/,
        // IOMAD: session-based company state, never SPA-swap.
        /\/blocks\/iomad/,
        /\/local\/iomad/
    ];

    var currentAbort = null;
    var prefetchCache = new Map();

    // ── Progress bar ──────────────────────────────────────────────

    function getOrCreateProgress() {
        var bar = document.getElementById(PROGRESS_ID);
        if (!bar) {
            bar = document.createElement('div');
            bar.id = PROGRESS_ID;
            bar.innerHTML = '<div class="sm-turbo-progress__bar"></div>';
            document.body.appendChild(bar);
        }
        return bar.firstElementChild;
    }

    // Progress bar disabled — no-ops so navigate() callsites don't change.
    function showProgress() {}
    function completeProgress() {}

    // ── Helpers ───────────────────────────────────────────────────

    function shouldIntercept(anchor) {
        if (anchor.origin !== location.origin) {
            return false;
        }
        if (anchor.hasAttribute('download') || anchor.target === '_blank') {
            return false;
        }
        if (anchor.pathname === location.pathname && anchor.hash) {
            return false;
        }
        if (anchor.hasAttribute('data-turbo') && anchor.getAttribute('data-turbo') === 'false') {
            return false;
        }
        var path = anchor.pathname + anchor.search;
        for (var i = 0; i < BYPASS_PATTERNS.length; i++) {
            if (BYPASS_PATTERNS[i].test(path)) {
                return false;
            }
        }
        return true;
    }

    function isHtmlResponse(resp) {
        var ct = resp.headers.get('content-type');
        return ct && ct.indexOf('text/html') !== -1;
    }

    function extractContent(doc) {
        var content = doc.querySelector(SWAP_SELECTOR);
        var secNav = doc.querySelector(SEC_NAV_SELECTOR);
        var pageHeader = doc.querySelector(PAGE_HEADER_SELECTOR);
        var primaryNavs = {};
        PRIMARY_NAV_SELECTORS.forEach(function(sel) {
            var el = doc.querySelector(sel);
            if (el) {
                primaryNavs[sel] = el;
            }
        });
        var title = doc.title;

        var styles = [];
        doc.querySelectorAll('body style, body link[rel="stylesheet"]').forEach(function(el) {
            styles.push(el.cloneNode(true));
        });

        var scripts = [];
        doc.querySelectorAll('body script').forEach(function(el) {
            scripts.push(el.textContent);
        });

        var bodyClasses = doc.body.className;

        return {
            content: content,
            secNav: secNav,
            pageHeader: pageHeader,
            primaryNavs: primaryNavs,
            title: title,
            styles: styles,
            scripts: scripts,
            bodyClasses: bodyClasses
        };
    }

    function swapContent(data) {
        var currentContent = document.querySelector(SWAP_SELECTOR);
        if (currentContent && data.content) {
            data.content.classList.add('sm-turbo-loading');
            currentContent.replaceWith(data.content);
            // eslint-disable-next-line no-unused-expressions
            data.content.offsetWidth;
            data.content.classList.remove('sm-turbo-loading');
        }

        var currentSecNav = document.querySelector(SEC_NAV_SELECTOR);
        if (data.secNav) {
            if (currentSecNav) {
                currentSecNav.replaceWith(data.secNav);
            } else {
                var pc = document.querySelector(SWAP_SELECTOR);
                if (pc) {
                    pc.parentNode.insertBefore(data.secNav, pc);
                }
            }
        } else if (currentSecNav) {
            currentSecNav.remove();
        }

        // Swap primary navigation(s) so the active item highlights correctly.
        PRIMARY_NAV_SELECTORS.forEach(function(sel) {
            var current = document.querySelector(sel);
            var fresh = data.primaryNavs[sel];
            if (current && fresh) {
                current.replaceWith(fresh);
            }
        });

        var currentPageHeader = document.querySelector(PAGE_HEADER_SELECTOR);
        if (data.pageHeader) {
            if (currentPageHeader) {
                currentPageHeader.replaceWith(data.pageHeader);
            }
        } else if (currentPageHeader) {
            currentPageHeader.remove();
        }

        document.querySelectorAll('[data-turbo-style]').forEach(function(el) {
            el.remove();
        });
        data.styles.forEach(function(el) {
            el.setAttribute('data-turbo-style', '');
            document.body.appendChild(el);
        });

        document.title = data.title;
        document.body.className = data.bodyClasses;

        data.scripts.forEach(function(code) {
            try {
                // eslint-disable-next-line no-eval
                eval(code);
            } catch (e) {
                // Silently ignore.
            }
        });

        window.scrollTo(0, 0);

        try {
            var tooltips = document.querySelectorAll('#page-content [data-bs-toggle="tooltip"]');
            tooltips.forEach(function(el) {
                new window.bootstrap.Tooltip(el);
            });
        } catch (_) {
            // Bootstrap may not be globally available.
        }
    }

    // ── Navigation ────────────────────────────────────────────────

    function navigate(url, pushState) {
        if (pushState === undefined) {
            pushState = true;
        }
        if (currentAbort) {
            currentAbort.abort();
        }
        currentAbort = new AbortController();

        showProgress();

        var cached = prefetchCache.get(url);
        var fetchPromise;

        if (cached) {
            fetchPromise = Promise.resolve(cached);
            prefetchCache.delete(url);
        } else {
            fetchPromise = fetch(url, {
                signal: currentAbort.signal,
                credentials: 'same-origin',
                headers: {'X-Turbo': '1'}
            }).then(function(resp) {
                if (!resp.ok || !isHtmlResponse(resp)) {
                    window.location.href = url;
                    return null;
                }
                return resp.text();
            });
        }

        fetchPromise.then(function(html) {
            if (!html) {
                return;
            }
            var parser = new DOMParser();
            var doc = parser.parseFromString(html, 'text/html');
            var data = extractContent(doc);
            if (!data.content) {
                window.location.href = url;
                return;
            }
            swapContent(data);
            if (pushState) {
                history.pushState({turbo: true}, '', url);
            }
            completeProgress();
            document.dispatchEvent(new CustomEvent('turbo:load', {detail: {url: url}}));
        }).catch(function(err) {
            if (err && err.name === 'AbortError') {
                return;
            }
            window.location.href = url;
        });
    }

    // ── Prefetch ──────────────────────────────────────────────────

    function prefetch(url) {
        if (prefetchCache.has(url)) {
            return;
        }
        prefetchCache.set(url, null);
        fetch(url, {credentials: 'same-origin', headers: {'X-Turbo': '1'}})
            .then(function(resp) {
                if (resp.ok && isHtmlResponse(resp)) {
                    return resp.text();
                }
                return null;
            })
            .then(function(html) {
                if (html) {
                    prefetchCache.set(url, html);
                } else {
                    prefetchCache.delete(url);
                }
            })
            .catch(function() {
                prefetchCache.delete(url);
            });
    }

    var COMMON_ROUTES = [
        '/my/',
        '/my/courses.php',
        '/user/profile.php',
        '/message/index.php',
        '/calendar/view.php'
    ];

    function getWwwRoot() {
        if (window.M && window.M.cfg && window.M.cfg.wwwroot) {
            return window.M.cfg.wwwroot;
        }
        return location.origin;
    }

    function prefetchCommonRoutes() {
        var root = getWwwRoot();
        COMMON_ROUTES.forEach(function(path) {
            try {
                var url = new URL(root + path).toString();
                if (url === location.href) {
                    return;
                }
                prefetch(url);
            } catch (_) {
                // ignore
            }
        });
    }

    // ── Init ──────────────────────────────────────────────────────

    function init() {
        // Guard against double-init across turbo swaps.
        if (window.__smTurboInitialized) {
            return;
        }
        window.__smTurboInitialized = true;

        document.addEventListener('click', function(e) {
            var anchor = e.target.closest && e.target.closest('a[href]');
            if (!anchor || e.ctrlKey || e.metaKey || e.shiftKey || e.altKey || e.button !== 0) {
                return;
            }
            if (!shouldIntercept(anchor)) {
                return;
            }
            e.preventDefault();
            navigate(anchor.href);
        });

        window.addEventListener('popstate', function() {
            navigate(location.href, false);
        });

        var hoverTimer = null;
        document.addEventListener('mouseover', function(e) {
            var anchor = e.target.closest && e.target.closest('a[href]');
            if (!anchor || !shouldIntercept(anchor)) {
                return;
            }
            clearTimeout(hoverTimer);
            hoverTimer = setTimeout(function() {
                prefetch(anchor.href);
            }, 200);
        });
        document.addEventListener('mouseout', function(e) {
            if (e.target.closest && e.target.closest('a[href]')) {
                clearTimeout(hoverTimer);
            }
        });

        document.addEventListener('submit', function(e) {
            var form = e.target;
            if (form.method && form.method.toUpperCase() !== 'GET') {
                return;
            }
            var action = form.action || location.href;
            try {
                var url = new URL(action);
                if (url.origin !== location.origin) {
                    return;
                }
                var formData = new FormData(form);
                formData.forEach(function(value, key) {
                    url.searchParams.set(key, value);
                });
                e.preventDefault();
                navigate(url.toString());
            } catch (_) {
                // Invalid URL — let the browser handle it.
            }
        });

        history.replaceState({turbo: true}, '');

        setTimeout(prefetchCommonRoutes, 1500);
        setInterval(function() {
            prefetchCache.clear();
            prefetchCommonRoutes();
        }, 3 * 60 * 1000);
    }

    return {init: init};
});
